// 辅助函数
export const getKnowledgePointsByChapter = (chapterId: string): KnowledgePointData[] => {
  return knowledgePoints.filter(kp => kp.chapterId === chapterId).sort((a, b) => a.order - b.order)
}

export const getKnowledgePointById = (id: string): KnowledgePointData | undefined => {
  return knowledgePoints.find(kp => kp.id === id)
}

export const getAllKnowledgePoints = (): KnowledgePointData[] => {
  return knowledgePoints.sort((a, b) => {
    if (a.chapterId !== b.chapterId) {
      return a.chapterId.localeCompare(b.chapterId)
    }
    return a.order - b.order
  })
}
